challenges.solution:
function applyToAll(array, fn) {
  const result = [];
  for (const item of array) {
    result.push(fn(item));
  }
  return result;
}

const numbers = [1, 2, 3, 4, 5];
const doubled = applyToAll(numbers, x => x * 2);
const asStrings = applyToAll(numbers, x => String(x));
